option.value:
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, useParams } from 'react-router-dom';
import { ChevronLeft, ChevronRight, User, Trophy, Download, Home, X, Zap } from 'lucide-react';
import CountdownTimer from '@/components/auction/CountdownTimer';
import PlaceBidModal from '@/components/auction/PlaceBidModal';
import AutoBidModal from '@/components/auction/AutoBidModal';
import FeatureAuctionModal from '@/components/auction/FeatureAuctionModal';
import { useAutoBid } from '@/hooks/useAutoBid';
import { placeBid, generateReceipt } from '@/services/bidService';
import { getAuctionById } from '@/services/auctionService';
import { resolveImageUrl } from '@/services/imageService';
import { featureAuction } from '@/services/featuredService';
import { resolveTextAlignmentClass, resolveTextDirection } from '@/lib/textDirection';
import ImageWithRetry from '@/components/ui/ImageWithRetry';
import { useNow } from '@/hooks/useNow';

export default function AuctionDetailPage({ currentUser }) {
    const { t, i18n } = useTranslation('common');
    const navigate = useNavigate();
    const { auctionId } = useParams();
    const isAr = i18n.language === 'ar';

    const [auction, setAuction] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const [bidModalOpen, setBidModalOpen] = useState(false);
    const [bidLoading, setBidLoading] = useState(false);
    const [autoBidModalOpen, setAutoBidModalOpen] = useState(false);
    const [bidSubmitError, setBidSubmitError] = useState(null);
    const [isFeatured, setIsFeatured] = useState(false);
    const [featureLoading, setFeatureLoading] = useState(false);
    const [featureModalOpen, setFeatureModalOpen] = useState(false);
    const now = useNow();
    const nowDate = new Date(now);

    const { autoBid, cancelAutoBid, setAutoBid, isLoading: autoBidLoading } = useAutoBid(auctionId);

    // Fetch auction from API
    useEffect(() => {
        const fetchAuction = async () => {
            setLoading(true);
            try {
                const response = await getAuctionById(auctionId);
                console.log('Auction loaded:', response);
                setAuction(response);
                setIsFeatured(response?.isActivelyFeatured || false);
                setError(null);
            } catch (err) {
                console.error('Error loading auction:', err);
                setError(isAr ? 'فشل تحميل المزاد' : 'Failed to load auction');
            } finally {
                setLoading(false);
            }
        };

        if (auctionId) {
            fetchAuction();
        }
    }, [auctionId, isAr]);

    if (loading) {
        return (
            <div className="min-h-screen bg-[#F0F2F5] flex items-center justify-center">
                <div className="w-10 h-10 border-4 border-[#C5E0DC] border-t-[#2A9D8F] rounded-full animate-spin" />
            </div>
        );
    }

    if (error || !auction) {
        const isSeller = currentUser?.role === 'SELLER';
        return (
            <div className="min-h-screen bg-[#F0F2F5] flex items-center justify-center p-4">
                <div className="bg-white rounded-xl border border-[#E05252] p-6 text-center max-w-md">
                    <p className="text-[#E05252] font-semibold mb-4">{error || (isAr ? 'المزاد غير متاح' : 'Auction not available')}</p>
                    <button
                        onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                        className="flex items-center gap-2 justify-center w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-6 py-2 rounded-lg font-bold transition-colors"
                    >
                        <Home className="w-4 h-4" />
                        {isAr ? 'العودة للرئيسية' : 'Return to Home'}
                    </button>
                </div>
            </div>
        );
    }

    const isBuyer = currentUser?.role === 'BUYER';
    const isSeller = currentUser?.role === 'SELLER';
    const startDate = auction?.startDate ? new Date(auction.startDate) : null;
    const endDate = auction?.endDate ? new Date(auction.endDate) : null;
    const hasStarted = !startDate || startDate <= nowDate;
    const isEnded = auction?.status === 'COMPLETED' || auction?.status === 'ENDED';
    const isFailedBelowReserve = auction?.status === 'FAILED_BELOW_RESERVE';
    const hasEndTimePassed = endDate && endDate < nowDate;
    const auctionEnded = isEnded || isFailedBelowReserve || hasEndTimePassed;
    const isPendingAuction = auction?.status === 'PENDING' && !hasStarted && !auctionEnded;
    const isLiveAuction = !auctionEnded && hasStarted && (auction?.status === 'ACTIVE' || auction?.status === 'PENDING');

    const canBid = isBuyer && isLiveAuction;
    const currentPrice = Number(auction?.currentPrice);
    const startingPrice = Number(auction?.startingPrice);
    const hasBids = Number.isFinite(auction?.bidCount) ? auction.bidCount > 0 : (Number.isFinite(currentPrice) && Number.isFinite(startingPrice) ? currentPrice > startingPrice : !!currentPrice);
    const baseBid = currentPrice > 0 ? currentPrice : startingPrice;
    const minRequiredBid = hasBids
        ? Math.ceil(baseBid * 1.05)
        : Math.floor(startingPrice > 0 ? startingPrice : 0) + 1;
    const isWinner = isBuyer && auctionEnded && hasBids && auction?.highestBidder === currentUser?.username;

    const images = auction?.images || [];
    const currentImage = images[currentImageIndex];

    const handlePrevImage = () => {
        setCurrentImageIndex((prev) => (prev === 0 ? images.length - 1 : prev - 1));
    };

    const handleNextImage = () => {
        setCurrentImageIndex((prev) => (prev === images.length - 1 ? 0 : prev + 1));
    };

    const handlePlaceBid = async (amount) => {
        setBidLoading(true);
        try {
            await placeBid(auction.id, amount);
            setBidModalOpen(false);
            // Refresh auction data - in real scenario you'd fetch updated data
            alert(isAr ? 'تم تسجيل المزايدة بنجاح' : 'Bid placed successfully!');
        } catch (error) {
            alert(error.message || t('actionFailed'));
        } finally {
            setBidLoading(false);
        }
    };

    const handleGenerateReceipt = async () => {
        const now = new Date();
        const endDate = new Date(auction.endDate);
        if (now < endDate) {
            alert(isAr ? 'لا يمكن تحميل الإيصال قبل انتهاء المزاد' : 'Receipt can only be downloaded after the auction ends');
            return;
        }

        setBidLoading(true);
        try {
            await generateReceipt(auction.id);
            alert(isAr ? 'تم تحميل الإيصال بنجاح' : 'Receipt downloaded successfully!');
        } catch (err) {
            alert(err.message || (isAr ? 'فشل تحميل الإيصال' : 'Failed to generate receipt'));
        } finally {
            setBidLoading(false);
        }
    };

    const handleFeatureAuction = async (featuredEndDate) => {
        setFeatureLoading(true);
        try {
            await featureAuction(auction.id, featuredEndDate);
            setIsFeatured(true);
            alert(isAr ? 'تم عرض المنتج بنجاح' : 'Product featured successfully!');
        } catch (error) {
            alert(error.message || (isAr ? 'فشل عرض المنتج' : 'Failed to feature product'));
            throw error;
        } finally {
            setFeatureLoading(false);
        }
    };

    const titleDir = resolveTextDirection(auction?.title || '');
    const descriptionDir = resolveTextDirection(auction?.description || '');

    return (
        <div className="min-h-screen bg-[#F0F2F5] py-8" dir={isAr ? 'rtl' : 'ltr'}>
            <div className="container mx-auto px-4 max-w-6xl">
                {/* Back Button */}
                <button
                    onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                    className="flex items-center gap-2 text-[#2A9D8F] hover:text-[#1A7A6E] font-semibold mb-6 transition-colors"
                >
                    {isAr ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5" />}
                    {isAr ? 'العودة للرئيسية' : 'Back to Home'}
                </button>

                {/* Main Content */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Image Gallery - Left Side */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-xl border border-[#C5E0DC] overflow-hidden shadow-sm">
                            {/* Main Image */}
                            {images.length > 0 ? (
                                <div className="relative bg-[#F4FAFA] aspect-video flex items-center justify-center">
                                    <ImageWithRetry
                                        src={resolveImageUrl(currentImage.url, currentImage.createdAt || currentImage.id)}
                                        alt={`${auction.title} ${currentImageIndex + 1}`}
                                        className="w-full h-full object-contain"
                                    />

                                    {/* Navigation Arrows */}
                                    {images.length > 1 && (
                                        <>
                                            <button
                                                onClick={handlePrevImage}
                                                className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full transition-all shadow-md"
                                                aria-label="Previous image"
                                            >
                                                {isAr ? <ChevronRight className="w-6 h-6 text-[#2A9D8F]" /> : <ChevronLeft className="w-6 h-6 text-[#2A9D8F]" />}
                                            </button>
                                            <button
                                                onClick={handleNextImage}
                                                className="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full transition-all shadow-md"
                                                aria-label="Next image"
                                            >
                                                {isAr ? <ChevronLeft className="w-6 h-6 text-[#2A9D8F]" /> : <ChevronRight className="w-6 h-6 text-[#2A9D8F]" />}
                                            </button>
                                        </>
                                    )}

                                    {/* Image Counter */}
                                    {images.length > 1 && (
                                        <div className="absolute bottom-4 right-4 bg-black/50 text-white px-3 py-1 rounded-full text-sm font-semibold">
                                            {currentImageIndex + 1} / {images.length}
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="bg-[#F4FAFA] aspect-video flex items-center justify-center">
                                    <span className="text-[#C5E0DC] font-bold text-4xl">
                                        {isAr ? 'لا توجد صورة' : 'No Image'}
                                    </span>
                                </div>
                            )}

                            {/* Thumbnail Gallery */}
                            {images.length > 1 && (
                                <div className="p-4 bg-white border-t border-[#C5E0DC] grid grid-cols-4 gap-2">
                                    {images.map((image, index) => (
                                        <button
                                            key={index}
                                            onClick={() => setCurrentImageIndex(index)}
                                            className={`aspect-square rounded-lg overflow-hidden border-2 transition-all ${index === currentImageIndex
                                                    ? 'border-[#2A9D8F] ring-2 ring-[#2A9D8F]/30'
                                                    : 'border-[#C5E0DC] hover:border-[#2A9D8F]'
                                                }`}
                                        >
                                            <ImageWithRetry
                                                src={resolveImageUrl(image.url, image.createdAt || image.id)}
                                                alt={`Thumbnail ${index + 1}`}
                                                className="w-full h-full object-cover"
                                            />
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Description Section */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-6 mt-6 shadow-sm">
                            <h2 className="text-lg font-bold text-[#1A2E2C] mb-4">
                                {isAr ? 'الوصف الكامل' : 'Full Description'}
                            </h2>
                            <p
                                dir={descriptionDir}
                                className={`text-[#1A2E2C] text-sm leading-relaxed ${resolveTextAlignmentClass(auction?.description || '')}`}
                            >
                                {auction?.description}
                            </p>
                        </div>
                    </div>

                    {/* Auction Details - Right Side */}
                    <div className="lg:col-span-1 space-y-4">
                        {/* Seller Info */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                            <div className="flex items-center gap-3 mb-3">
                                <div className="w-10 h-10 rounded-full bg-[#EAF7F5] flex items-center justify-center shrink-0">
                                    <User className="w-5 h-5 text-[#2A9D8F]" />
                                </div>
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'البائع' : 'Seller'}</p>
                                    <h3 className="font-bold text-[#1A2E2C]">
                                        {auction?.sellerName || (isAr ? 'بائع' : 'Seller')}
                                    </h3>
                                </div>
                            </div>
                            <div className="pt-3 border-t border-[#C5E0DC]">
                                <p className="text-xs text-[#6B9E99]">{isAr ? 'صالة المزاد' : 'Auction House'}</p>
                                <p className="font-semibold text-[#1A2E2C]">{auction?.auctionHouseName}</p>
                            </div>
                        </div>

                        {/* Title */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                            <h1
                                dir={titleDir}
                                className={`font-bold text-2xl text-[#1A2E2C] ${resolveTextAlignmentClass(auction?.title || '')}`}
                            >
                                {auction?.title}
                            </h1>
                        </div>

                        {/* Price Section */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-6 shadow-sm">
                            <div className="mb-4">
                                <p className="text-xs text-[#6B9E99] mb-1">
                                    {isAr ? 'السعر الحالي' : 'Current Price'}
                                </p>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-4xl font-bold text-[#2A9D8F] pulse-animation" dir="ltr">
                                        {currentPrice}
                                    </span>
                                    <span className="text-lg font-semibold text-[#6B9E99]">﷼</span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3 pt-4 border-t border-[#C5E0DC]">
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'السعر الأولي' : 'Starting Price'}</p>
                                    <p className="font-semibold text-[#1A2E2C]" dir={isAr ? 'rtl' : 'ltr'}>{startingPrice} ﷼</p>
                                </div>
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'عدد المزايدات' : 'Bids'}</p>
                                    <p className="font-semibold text-[#1A2E2C]">{auction?.bidCount || 0}</p>
                                </div>
                            </div>
                        </div>

                        {/* Countdown or Status */}
                        {isPendingAuction && auction?.startDate && (
                            <div className="bg-[#FFF9E6] border border-[#FFD54D]/50 rounded-xl py-4 px-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#B8860B] mb-2">
                                    {isAr ? 'قيد الانتظار' : 'Pending'}
                                </p>
                                <p className="text-xs font-semibold text-[#B8860B] mb-2">
                                    {isAr ? 'يبدأ بعد' : 'Starts In'}
                                </p>
                                <CountdownTimer targetDate={auction.startDate} mode="start" />
                            </div>
                        )}

                        {isLiveAuction && !auctionEnded && (
                            <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#6B9E99] mb-2">
                                    {isAr ? 'الوقت المتبقي' : 'Time Left'}
                                </p>
                                <CountdownTimer targetDate={auction.endDate} mode="end" />
                            </div>
                        )}


                        {/* Auction Status */}
                        {auctionEnded && (
                            <div className="bg-gradient-to-r from-[#E05252]/10 to-[#E05252]/5 border border-[#E05252]/30 rounded-xl py-4 px-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#E05252]">
                                    {isFailedBelowReserve
                                        ? (isAr ? '❌ فشل - أقل من الحد الأدنى للبيع' : '❌ Failed - Below Reserve Price')
                                        : (isAr ? '❌ انتهى المزاد' : '❌ Auction Ended')}
                                </p>
                            </div>
                        )}

                        {/* Winner Badge */}
                        {isWinner && (
                            <div className="bg-gradient-to-r from-[#2A9D8F] to-[#1A7A6E] rounded-xl py-4 px-4 text-white shadow-sm">
                                <div className="flex items-center gap-2 mb-2">
                                    <Trophy className="w-5 h-5" />
                                    <p className="font-bold">{isAr ? ' أنت الفائز!' : ' You Won!'}</p>
                                </div>
                            </div>
                        )}

                        {/* Auto-Bid Indicator */}
                        {canBid && autoBid && (
                            <div className="bg-[#EAF7F5] border border-[#2A9D8F] rounded-xl p-3 shadow-sm flex items-center justify-between mb-4">
                                <div>
                                    <p className="text-xs text-[#2A9D8F] font-bold flex items-center gap-1">
                                        <span className="w-1.5 h-1.5 bg-[#2A9D8F] rounded-full animate-pulse"></span>
                                        {t('autoBid.active')}
                                    </p>
                                    <p className="text-sm text-[#1A2E2C] font-semibold mt-0.5">
                                        {t('autoBid.activeMax')}: {autoBid.maxAmount} ر.س
                                    </p>
                                </div>
                                <button
                                    onClick={() => cancelAutoBid()}
                                    disabled={autoBidLoading}
                                    className="p-1.5 bg-white text-[#E05252] hover:bg-[#E05252] hover:text-white rounded-lg transition-colors border border-[#E05252]/20"
                                    title={t('autoBid.cancel')}
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            </div>
                        )}

                        {/* Action Buttons */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm space-y-2">
                            {canBid && (
                                <div className="grid grid-cols-2 gap-2">
                                    <button
                                        onClick={() => setBidModalOpen(true)}
                                        disabled={bidLoading}
                                        className="w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 text-sm"
                                    >
                                        {isAr ? 'مزايدة الآن' : 'Place Bid Now'}
                                    </button>
                                    <button
                                        onClick={() => setAutoBidModalOpen(true)}
                                        disabled={bidLoading || autoBidLoading}
                                        className="w-full bg-[#EAF7F5] hover:bg-[#D5EFEC] text-[#2A9D8F] border border-[#2A9D8F] px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 text-sm"
                                    >
                                        {isAr ? 'مزايدة تلقائية' : 'Auto-Bid'}
                                    </button>
                                </div>
                            )}

                            {isWinner && (
                                <button
                                    onClick={handleGenerateReceipt}
                                    disabled={bidLoading}
                                    className="w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 flex items-center justify-center gap-2 text-sm"
                                >
                                    <Download className="w-4 h-4" />
                                    {isAr ? 'تحميل الإيصال' : 'Download Receipt'}
                                </button>
                            )}

                            {isSeller && isLiveAuction && !isFeatured && (
                                <button
                                    onClick={() => setFeatureModalOpen(true)}
                                    disabled={featureLoading}
                                    className="w-full bg-gradient-to-r from-[#2A9D8F] to-[#1A7A6E] hover:from-[#1A7A6E] hover:to-[#0D5A52] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 flex items-center justify-center gap-2 text-sm"
                                >
                                    <Zap className="w-4 h-4" />
                                    {t('featureThisAuction')}
                                </button>
                            )}

                            {isSeller && isFeatured && (
                                <div className="w-full bg-[#EAF7F5] border border-[#2A9D8F] text-[#2A9D8F] px-4 py-3 rounded-lg font-bold flex items-center justify-center gap-2 text-sm">
                                    <Zap className="w-4 h-4" />
                                    {t('featuredActive')}
                                </div>
                            )}

                            <button
                                onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                                className="w-full bg-[#F4FAFA] hover:bg-[#E2F1EF] text-[#2A9D8F] px-4 py-3 rounded-lg font-bold transition-colors text-sm"
                            >
                                {isAr ? '← العودة' : 'Back →'}
                            </button>
                        </div>

                        {/* Winner Information - For Seller */}
                        {auctionEnded && isSeller && hasBids && auction?.highestBidder && (
                            <div className="bg-[#EAF7F5] border border-[#2A9D8F] rounded-xl py-4 px-4 shadow-sm">
                                <div className="flex items-center gap-2 mb-3">
                                    <Trophy className="w-5 h-5 text-[#2A9D8F]" />
                                    <p className="font-semibold text-[#2A9D8F]">
                                        {isAr ? 'الفائز' : 'Winner'}
                                    </p>
                                </div>
                                <p className="text-[#1A2E2C] font-bold mb-2">{auction.highestBidder}</p>
                                {auction.highestBidderEmail && (
                                    <p className="text-xs text-[#6B9E99]" dir="ltr">
                                        {isAr ? 'البريد الإلكتروني' : 'Email'}: {auction.highestBidderEmail}
                                    </p>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Bid Modal */}
            <PlaceBidModal
                open={bidModalOpen}
                onOpenChange={setBidModalOpen}
                currentPrice={currentPrice}
                minBid={minRequiredBid}
                hasPreviousBid={hasBids}
                onBidSubmit={handlePlaceBid}
                loading={bidLoading}
            />

            {/* Auto Bid Modal */}
            <AutoBidModal
                open={autoBidModalOpen}
                onOpenChange={setAutoBidModalOpen}
                currentPrice={currentPrice}
                minBid={minRequiredBid}
                autoBid={autoBid}
                apiLoading={autoBidLoading}
                setAutoBid={setAutoBid}
                cancelAutoBid={cancelAutoBid}
            />

            {/* Feature Auction Modal */}
            <FeatureAuctionModal
                open={featureModalOpen}
                onOpenChange={setFeatureModalOpen}
                auctionTitle={auction?.title}
                auctionEndDate={auction?.endDate}
                onFeature={handleFeatureAuction}
                loading={featureLoading}
            />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, useParams } from 'react-router-dom';
import { ChevronLeft, ChevronRight, User, Trophy, Download, Home, X, Zap } from 'lucide-react';
import CountdownTimer from '@/components/auction/CountdownTimer';
import PlaceBidModal from '@/components/auction/PlaceBidModal';
import AutoBidModal from '@/components/auction/AutoBidModal';
import FeatureAuctionModal from '@/components/auction/FeatureAuctionModal';
import { useAutoBid } from '@/hooks/useAutoBid';
import { placeBid, generateReceipt } from '@/services/bidService';
import { getAuctionById } from '@/services/auctionService';
import { resolveImageUrl } from '@/services/imageService';
import { featureAuction } from '@/services/featuredService';
import { resolveTextAlignmentClass, resolveTextDirection } from '@/lib/textDirection';
import ImageWithRetry from '@/components/ui/ImageWithRetry';
import { useNow } from '@/hooks/useNow';
import { toast } from 'sonner';

export default function AuctionDetailPage({ currentUser }) {
    const { t, i18n } = useTranslation('common');
    const navigate = useNavigate();
    const { auctionId } = useParams();
    const isAr = i18n.language === 'ar';

    const [auction, setAuction] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const [bidModalOpen, setBidModalOpen] = useState(false);
    const [bidLoading, setBidLoading] = useState(false);
    const [autoBidModalOpen, setAutoBidModalOpen] = useState(false);
    const [bidSubmitError, setBidSubmitError] = useState(null);
    const [isFeatured, setIsFeatured] = useState(false);
    const [featureLoading, setFeatureLoading] = useState(false);
    const [featureModalOpen, setFeatureModalOpen] = useState(false);
    const now = useNow();
    const nowDate = new Date(now);

    const { autoBid, cancelAutoBid, setAutoBid, isLoading: autoBidLoading } = useAutoBid(auctionId);

    // Fetch auction from API
    useEffect(() => {
        const fetchAuction = async () => {
            setLoading(true);
            try {
                const response = await getAuctionById(auctionId);
                console.log('Auction loaded:', response);
                setAuction(response);
                setIsFeatured(response?.isActivelyFeatured || false);
                setError(null);
            } catch (err) {
                console.error('Error loading auction:', err);
                setError(isAr ? 'فشل تحميل المزاد' : 'Failed to load auction');
            } finally {
                setLoading(false);
            }
        };

        if (auctionId) {
            fetchAuction();
        }
    }, [auctionId, isAr]);

    if (loading) {
        return (
            <div className="min-h-screen bg-[#F0F2F5] flex items-center justify-center">
                <div className="w-10 h-10 border-4 border-[#C5E0DC] border-t-[#2A9D8F] rounded-full animate-spin" />
            </div>
        );
    }

    if (error || !auction) {
        const isSeller = currentUser?.role === 'SELLER';
        return (
            <div className="min-h-screen bg-[#F0F2F5] flex items-center justify-center p-4">
                <div className="bg-white rounded-xl border border-[#E05252] p-6 text-center max-w-md">
                    <p className="text-[#E05252] font-semibold mb-4">{error || (isAr ? 'المزاد غير متاح' : 'Auction not available')}</p>
                    <button
                        onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                        className="flex items-center gap-2 justify-center w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-6 py-2 rounded-lg font-bold transition-colors"
                    >
                        <Home className="w-4 h-4" />
                        {isAr ? 'العودة للرئيسية' : 'Return to Home'}
                    </button>
                </div>
            </div>
        );
    }

    const isBuyer = currentUser?.role === 'BUYER';
    const isSeller = currentUser?.role === 'SELLER';
    const startDate = auction?.startDate ? new Date(auction.startDate) : null;
    const endDate = auction?.endDate ? new Date(auction.endDate) : null;
    const hasStarted = !startDate || startDate <= nowDate;
    const isEnded = auction?.status === 'COMPLETED' || auction?.status === 'ENDED';
    const isFailedBelowReserve = auction?.status === 'FAILED_BELOW_RESERVE';
    const hasEndTimePassed = endDate && endDate < nowDate;
    const auctionEnded = isEnded || isFailedBelowReserve || hasEndTimePassed;
    const isPendingAuction = auction?.status === 'PENDING' && !hasStarted && !auctionEnded;
    const isLiveAuction = !auctionEnded && hasStarted && (auction?.status === 'ACTIVE' || auction?.status === 'PENDING');

    const canBid = isBuyer && isLiveAuction;
    const currentPrice = Number(auction?.currentPrice);
    const startingPrice = Number(auction?.startingPrice);
    const hasBids = Number.isFinite(auction?.bidCount) ? auction.bidCount > 0 : (Number.isFinite(currentPrice) && Number.isFinite(startingPrice) ? currentPrice > startingPrice : !!currentPrice);
    const baseBid = currentPrice > 0 ? currentPrice : startingPrice;
    const minRequiredBid = hasBids
        ? Math.ceil(baseBid * 1.05)
        : Math.floor(startingPrice > 0 ? startingPrice : 0) + 1;
    const isWinner = isBuyer && auctionEnded && hasBids && auction?.highestBidder === currentUser?.username;

    const images = auction?.images || [];
    const currentImage = images[currentImageIndex];

    const handlePrevImage = () => {
        setCurrentImageIndex((prev) => (prev === 0 ? images.length - 1 : prev - 1));
    };

    const handleNextImage = () => {
        setCurrentImageIndex((prev) => (prev === images.length - 1 ? 0 : prev + 1));
    };

    const handlePlaceBid = async (amount) => {
        setBidLoading(true);
        try {
            await placeBid(auction.id, amount);
            setBidModalOpen(false);
            // Refresh auction data - in real scenario you'd fetch updated data
            toast.success(isAr ? 'تم تسجيل المزايدة بنجاح' : 'Bid placed successfully!');
        } catch (error) {
            toast.error(error.message || t('actionFailed'));
        } finally {
            setBidLoading(false);
        }
    };

    const handleGenerateReceipt = async () => {
        const now = new Date();
        const endDate = new Date(auction.endDate);
        if (now < endDate) {
            toast.error(isAr ? 'لا يمكن تحميل الإيصال قبل انتهاء المزاد' : 'Receipt can only be downloaded after the auction ends');
            return;
        }

        setBidLoading(true);
        try {
            await generateReceipt(auction.id);
            toast.success(isAr ? 'تم تحميل الإيصال بنجاح' : 'Receipt downloaded successfully!');
        } catch (err) {
            toast.error(err.message || (isAr ? 'فشل تحميل الإيصال' : 'Failed to generate receipt'));
        } finally {
            setBidLoading(false);
        }
    };

    const handleFeatureAuction = async (featuredEndDate) => {
        setFeatureLoading(true);
        try {
            await featureAuction(auction.id, featuredEndDate);
            setIsFeatured(true);
            toast.success(isAr ? 'تم عرض المنتج بنجاح' : 'Product featured successfully!');
        } catch (error) {
            toast.error(error.message || (isAr ? 'فشل عرض المنتج' : 'Failed to feature product'));
            throw error;
        } finally {
            setFeatureLoading(false);
        }
    };

    const titleDir = resolveTextDirection(auction?.title || '');
    const descriptionDir = resolveTextDirection(auction?.description || '');

    return (
        <div className="min-h-screen bg-[#F0F2F5] py-8" dir={isAr ? 'rtl' : 'ltr'}>
            <div className="container mx-auto px-4 max-w-6xl">
                {/* Back Button */}
                <button
                    onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                    className="flex items-center gap-2 text-[#2A9D8F] hover:text-[#1A7A6E] font-semibold mb-6 transition-colors"
                >
                    {isAr ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5" />}
                    {isAr ? 'العودة للرئيسية' : 'Back to Home'}
                </button>

                {/* Main Content */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Image Gallery - Left Side */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-xl border border-[#C5E0DC] overflow-hidden shadow-sm">
                            {/* Main Image */}
                            {images.length > 0 ? (
                                <div className="relative bg-[#F4FAFA] aspect-video flex items-center justify-center">
                                    <ImageWithRetry
                                        src={resolveImageUrl(currentImage.url, currentImage.createdAt || currentImage.id)}
                                        alt={`${auction.title} ${currentImageIndex + 1}`}
                                        className="w-full h-full object-contain"
                                    />

                                    {/* Navigation Arrows */}
                                    {images.length > 1 && (
                                        <>
                                            <button
                                                onClick={handlePrevImage}
                                                className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full transition-all shadow-md"
                                                aria-label="Previous image"
                                            >
                                                {isAr ? <ChevronRight className="w-6 h-6 text-[#2A9D8F]" /> : <ChevronLeft className="w-6 h-6 text-[#2A9D8F]" />}
                                            </button>
                                            <button
                                                onClick={handleNextImage}
                                                className="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full transition-all shadow-md"
                                                aria-label="Next image"
                                            >
                                                {isAr ? <ChevronLeft className="w-6 h-6 text-[#2A9D8F]" /> : <ChevronRight className="w-6 h-6 text-[#2A9D8F]" />}
                                            </button>
                                        </>
                                    )}

                                    {/* Image Counter */}
                                    {images.length > 1 && (
                                        <div className="absolute bottom-4 right-4 bg-black/50 text-white px-3 py-1 rounded-full text-sm font-semibold">
                                            {currentImageIndex + 1} / {images.length}
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="bg-[#F4FAFA] aspect-video flex items-center justify-center">
                                    <span className="text-[#C5E0DC] font-bold text-4xl">
                                        {isAr ? 'لا توجد صورة' : 'No Image'}
                                    </span>
                                </div>
                            )}

                            {/* Thumbnail Gallery */}
                            {images.length > 1 && (
                                <div className="p-4 bg-white border-t border-[#C5E0DC] grid grid-cols-4 gap-2">
                                    {images.map((image, index) => (
                                        <button
                                            key={index}
                                            onClick={() => setCurrentImageIndex(index)}
                                            className={`aspect-square rounded-lg overflow-hidden border-2 transition-all ${index === currentImageIndex
                                                    ? 'border-[#2A9D8F] ring-2 ring-[#2A9D8F]/30'
                                                    : 'border-[#C5E0DC] hover:border-[#2A9D8F]'
                                                }`}
                                        >
                                            <ImageWithRetry
                                                src={resolveImageUrl(image.url, image.createdAt || image.id)}
                                                alt={`Thumbnail ${index + 1}`}
                                                className="w-full h-full object-cover"
                                            />
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Description Section */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-6 mt-6 shadow-sm">
                            <h2 className="text-lg font-bold text-[#1A2E2C] mb-4">
                                {isAr ? 'الوصف الكامل' : 'Full Description'}
                            </h2>
                            <p
                                dir={descriptionDir}
                                className={`text-[#1A2E2C] text-sm leading-relaxed ${resolveTextAlignmentClass(auction?.description || '')}`}
                            >
                                {auction?.description}
                            </p>
                        </div>
                    </div>

                    {/* Auction Details - Right Side */}
                    <div className="lg:col-span-1 space-y-4">
                        {/* Seller Info */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                            <div className="flex items-center gap-3 mb-3">
                                <div className="w-10 h-10 rounded-full bg-[#EAF7F5] flex items-center justify-center shrink-0">
                                    <User className="w-5 h-5 text-[#2A9D8F]" />
                                </div>
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'البائع' : 'Seller'}</p>
                                    <h3 className="font-bold text-[#1A2E2C]">
                                        {auction?.sellerName || (isAr ? 'بائع' : 'Seller')}
                                    </h3>
                                </div>
                            </div>
                            <div className="pt-3 border-t border-[#C5E0DC]">
                                <p className="text-xs text-[#6B9E99]">{isAr ? 'صالة المزاد' : 'Auction House'}</p>
                                <p className="font-semibold text-[#1A2E2C]">{auction?.auctionHouseName}</p>
                            </div>
                        </div>

                        {/* Title */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                            <h1
                                dir={titleDir}
                                className={`font-bold text-2xl text-[#1A2E2C] ${resolveTextAlignmentClass(auction?.title || '')}`}
                            >
                                {auction?.title}
                            </h1>
                        </div>

                        {/* Price Section */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-6 shadow-sm">
                            <div className="mb-4">
                                <p className="text-xs text-[#6B9E99] mb-1">
                                    {isAr ? 'السعر الحالي' : 'Current Price'}
                                </p>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-4xl font-bold text-[#2A9D8F] pulse-animation" dir="ltr">
                                        {currentPrice}
                                    </span>
                                    <span className="text-lg font-semibold text-[#6B9E99]">﷼</span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3 pt-4 border-t border-[#C5E0DC]">
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'السعر الأولي' : 'Starting Price'}</p>
                                    <p className="font-semibold text-[#1A2E2C]" dir={isAr ? 'rtl' : 'ltr'}>{startingPrice} ﷼</p>
                                </div>
                                <div>
                                    <p className="text-xs text-[#6B9E99]">{isAr ? 'عدد المزايدات' : 'Bids'}</p>
                                    <p className="font-semibold text-[#1A2E2C]">{auction?.bidCount || 0}</p>
                                </div>
                            </div>
                        </div>

                        {/* Countdown or Status */}
                        {isPendingAuction && auction?.startDate && (
                            <div className="bg-[#FFF9E6] border border-[#FFD54D]/50 rounded-xl py-4 px-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#B8860B] mb-2">
                                    {isAr ? 'قيد الانتظار' : 'Pending'}
                                </p>
                                <p className="text-xs font-semibold text-[#B8860B] mb-2">
                                    {isAr ? 'يبدأ بعد' : 'Starts In'}
                                </p>
                                <CountdownTimer targetDate={auction.startDate} mode="start" />
                            </div>
                        )}

                        {isLiveAuction && !auctionEnded && (
                            <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#6B9E99] mb-2">
                                    {isAr ? 'الوقت المتبقي' : 'Time Left'}
                                </p>
                                <CountdownTimer targetDate={auction.endDate} mode="end" />
                            </div>
                        )}


                        {/* Auction Status */}
                        {auctionEnded && (
                            <div className="bg-gradient-to-r from-[#E05252]/10 to-[#E05252]/5 border border-[#E05252]/30 rounded-xl py-4 px-4 shadow-sm">
                                <p className="text-sm font-semibold text-[#E05252]">
                                    {isFailedBelowReserve
                                        ? (isAr ? '❌ فشل - أقل من الحد الأدنى للبيع' : '❌ Failed - Below Reserve Price')
                                        : (isAr ? '❌ انتهى المزاد' : '❌ Auction Ended')}
                                </p>
                            </div>
                        )}

                        {/* Winner Badge */}
                        {isWinner && (
                            <div className="bg-gradient-to-r from-[#2A9D8F] to-[#1A7A6E] rounded-xl py-4 px-4 text-white shadow-sm">
                                <div className="flex items-center gap-2 mb-2">
                                    <Trophy className="w-5 h-5" />
                                    <p className="font-bold">{isAr ? ' أنت الفائز!' : ' You Won!'}</p>
                                </div>
                            </div>
                        )}

                        {/* Auto-Bid Indicator */}
                        {canBid && autoBid && (
                            <div className="bg-[#EAF7F5] border border-[#2A9D8F] rounded-xl p-3 shadow-sm flex items-center justify-between mb-4">
                                <div>
                                    <p className="text-xs text-[#2A9D8F] font-bold flex items-center gap-1">
                                        <span className="w-1.5 h-1.5 bg-[#2A9D8F] rounded-full animate-pulse"></span>
                                        {t('autoBid.active')}
                                    </p>
                                    <p className="text-sm text-[#1A2E2C] font-semibold mt-0.5">
                                        {t('autoBid.activeMax')}: {autoBid.maxAmount} ر.س
                                    </p>
                                </div>
                                <button
                                    onClick={() => cancelAutoBid()}
                                    disabled={autoBidLoading}
                                    className="p-1.5 bg-white text-[#E05252] hover:bg-[#E05252] hover:text-white rounded-lg transition-colors border border-[#E05252]/20"
                                    title={t('autoBid.cancel')}
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            </div>
                        )}

                        {/* Action Buttons */}
                        <div className="bg-white rounded-xl border border-[#C5E0DC] p-4 shadow-sm space-y-2">
                            {canBid && (
                                <div className="grid grid-cols-2 gap-2">
                                    <button
                                        onClick={() => setBidModalOpen(true)}
                                        disabled={bidLoading}
                                        className="w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 text-sm"
                                    >
                                        {isAr ? 'مزايدة الآن' : 'Place Bid Now'}
                                    </button>
                                    <button
                                        onClick={() => setAutoBidModalOpen(true)}
                                        disabled={bidLoading || autoBidLoading}
                                        className="w-full bg-[#EAF7F5] hover:bg-[#D5EFEC] text-[#2A9D8F] border border-[#2A9D8F] px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 text-sm"
                                    >
                                        {isAr ? 'مزايدة تلقائية' : 'Auto-Bid'}
                                    </button>
                                </div>
                            )}

                            {isWinner && (
                                <button
                                    onClick={handleGenerateReceipt}
                                    disabled={bidLoading}
                                    className="w-full bg-[#2A9D8F] hover:bg-[#1A7A6E] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 flex items-center justify-center gap-2 text-sm"
                                >
                                    <Download className="w-4 h-4" />
                                    {isAr ? 'تحميل الإيصال' : 'Download Receipt'}
                                </button>
                            )}

                            {isSeller && isLiveAuction && !isFeatured && (
                                <button
                                    onClick={() => setFeatureModalOpen(true)}
                                    disabled={featureLoading}
                                    className="w-full bg-gradient-to-r from-[#2A9D8F] to-[#1A7A6E] hover:from-[#1A7A6E] hover:to-[#0D5A52] text-white px-4 py-3 rounded-lg font-bold transition-colors disabled:opacity-50 flex items-center justify-center gap-2 text-sm"
                                >
                                    <Zap className="w-4 h-4" />
                                    {t('featureThisAuction')}
                                </button>
                            )}

                            {isSeller && isFeatured && (
                                <div className="w-full bg-[#EAF7F5] border border-[#2A9D8F] text-[#2A9D8F] px-4 py-3 rounded-lg font-bold flex items-center justify-center gap-2 text-sm">
                                    <Zap className="w-4 h-4" />
                                    {t('featuredActive')}
                                </div>
                            )}

                            <button
                                onClick={() => isSeller ? navigate('/seller-dashboard') : navigate('/')}
                                className="w-full bg-[#F4FAFA] hover:bg-[#E2F1EF] text-[#2A9D8F] px-4 py-3 rounded-lg font-bold transition-colors text-sm"
                            >
                                {isAr ? '← العودة' : 'Back →'}
                            </button>
                        </div>

                        {/* Winner Information - For Seller */}
                        {auctionEnded && isSeller && hasBids && auction?.highestBidder && (
                            <div className="bg-[#EAF7F5] border border-[#2A9D8F] rounded-xl py-4 px-4 shadow-sm">
                                <div className="flex items-center gap-2 mb-3">
                                    <Trophy className="w-5 h-5 text-[#2A9D8F]" />
                                    <p className="font-semibold text-[#2A9D8F]">
                                        {isAr ? 'الفائز' : 'Winner'}
                                    </p>
                                </div>
                                <p className="text-[#1A2E2C] font-bold mb-2">{auction.highestBidder}</p>
                                {auction.highestBidderEmail && (
                                    <p className="text-xs text-[#6B9E99]" dir="ltr">
                                        {isAr ? 'البريد الإلكتروني' : 'Email'}: {auction.highestBidderEmail}
                                    </p>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Bid Modal */}
            <PlaceBidModal
                open={bidModalOpen}
                onOpenChange={setBidModalOpen}
                currentPrice={currentPrice}
                minBid={minRequiredBid}
                hasPreviousBid={hasBids}
                onBidSubmit={handlePlaceBid}
                loading={bidLoading}
            />

            {/* Auto Bid Modal */}
            <AutoBidModal
                open={autoBidModalOpen}
                onOpenChange={setAutoBidModalOpen}
                currentPrice={currentPrice}
                minBid={minRequiredBid}
                autoBid={autoBid}
                apiLoading={autoBidLoading}
                setAutoBid={setAutoBid}
                cancelAutoBid={cancelAutoBid}
            />

            {/* Feature Auction Modal */}
            <FeatureAuctionModal
                open={featureModalOpen}
                onOpenChange={setFeatureModalOpen}
                auctionTitle={auction?.title}
                auctionEndDate={auction?.endDate}
                onFeature={handleFeatureAuction}
                loading={featureLoading}
            />
        </div>
    );
}

package org.example.mazadat.Service;

import com.itextpdf.io.font.PdfEncodings;
import com.itextpdf.kernel.font.PdfFont;
import com.itextpdf.kernel.font.PdfFontFactory;
import com.itextpdf.io.image.ImageData;
import com.itextpdf.io.image.ImageDataFactory;
import com.itextpdf.kernel.pdf.PdfDocument;
import com.itextpdf.kernel.pdf.PdfWriter;
import com.itextpdf.layout.Document;
import com.itextpdf.layout.element.Image;
import com.itextpdf.layout.element.Paragraph;
import com.itextpdf.layout.element.Table;
import com.itextpdf.layout.properties.TextAlignment;
import lombok.RequiredArgsConstructor;
import org.example.mazadat.Api.ApiException;
import org.example.mazadat.Model.Auction;
import org.example.mazadat.Model.Buyer;
import org.example.mazadat.Repository.AuctionRepository;
import org.example.mazadat.Repository.BuyerRepository;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.nio.charset.StandardCharsets;

@Service
@RequiredArgsConstructor
public class ReceiptService {

    private final AuctionRepository auctionRepository;
    private final BuyerRepository buyerRepository;

    public byte[] generateReceiptPDF(Integer auctionId, Integer buyerId) {
        // Fetch auction
        Auction auction = auctionRepository.findById(auctionId).orElse(null);
        if (auction == null) {
            throw new ApiException("Auction not found");
        }

        // Verify auction has ended
        LocalDateTime now = LocalDateTime.now();
        if (auction.getEndDate() != null && now.isBefore(auction.getEndDate())) {
            throw new ApiException("Auction has not ended yet. Receipt can only be downloaded after the auction ends.");
        }

        // Fetch buyer
        Buyer buyer = buyerRepository.findById(buyerId).orElse(null);
        if (buyer == null) {
            throw new ApiException("Buyer not found");
        }

        // Verify buyer is the winner
        if (auction.getHighestBidder() == null || !auction.getHighestBidder().equals(buyer.getUser().getUsername())) {
            throw new ApiException("Only the auction winner can generate a receipt");
        }

        // Update auction status to ENDED if not already
        if (auction.getStatus() == null || !auction.getStatus().equals("ENDED")) {
            auction.setStatus("ENDED");
            auctionRepository.save(auction);
        }

        byte[] pdfBytes = createPDF(auction, buyer);
        if (pdfBytes == null || pdfBytes.length < 16) {
            throw new ApiException("Generated receipt is empty");
        }

        String pdfHeader = new String(pdfBytes, 0, 4, StandardCharsets.US_ASCII);
        if (!"%PDF".equals(pdfHeader)) {
            throw new ApiException("Generated receipt is invalid");
        }

        return pdfBytes;
    }

    private byte[] createPDF(Auction auction, Buyer buyer) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            PdfWriter writer = new PdfWriter(baos);
            PdfDocument pdfDoc = new PdfDocument(writer);
            Document doc = new Document(pdfDoc);
            PdfFont unicodeFont = loadUnicodeFont();
            doc.setFont(unicodeFont);

            // Add logo
            try {
                ClassPathResource resource = new ClassPathResource("static/logos/mazadat_green_logo.png");
                InputStream inputStream = resource.getInputStream();
                ImageData imageData = ImageDataFactory.create(inputStreamToByteArray(inputStream));
                Image logo = new Image(imageData).setWidth(100).setHeight(100);
                doc.add(logo);
            } catch (Exception e) {
                // Logo not found, continue without it
            }

            // Title
            Paragraph title = new Paragraph("MAZADAT AUCTION RECEIPT")
                    .setFontSize(24)
                    .setBold()
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(title);

            // Receipt date
            String formattedDate = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
            Paragraph dateP = new Paragraph("Receipt Generated: " + formattedDate)
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(dateP);

            // Divider
            doc.add(new Paragraph("_".repeat(80)).setTextAlignment(TextAlignment.CENTER).setMarginBottom(20));

            // Auction Details
            Paragraph auctionTitle = new Paragraph("AUCTION DETAILS")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(auctionTitle);

            Table auctionTable = new Table(2).setWidth(500);
            auctionTable.addCell(new Paragraph("Auction ID:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(String.valueOf(auction.getId())).setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction Name:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getTitle() != null ? auction.getTitle() : "N/A").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction Description:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getDescription() != null ? auction.getDescription() : "N/A").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Selling Price:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getCurrentPrice() + " SR").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph("Auction End Date:").setFont(unicodeFont));
            auctionTable.addCell(new Paragraph(auction.getEndDate() != null ?
                    auction.getEndDate().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss")) : "N/A").setFont(unicodeFont));
            doc.add(auctionTable);

            // Seller Details
            Paragraph sellerTitle = new Paragraph("SELLER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(sellerTitle);

            Table sellerTable = new Table(2).setWidth(500);
            sellerTable.addCell(new Paragraph("Seller Name:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getUser().getUsername()).setFont(unicodeFont));
            sellerTable.addCell(new Paragraph("Seller Email:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getUser().getEmail()).setFont(unicodeFont));
            sellerTable.addCell(new Paragraph("Iban:").setFont(unicodeFont));
            sellerTable.addCell(new Paragraph(auction.getSeller().getIban() != null ?
                    auction.getSeller().getIban() : "Not provided").setFont(unicodeFont));
            doc.add(sellerTable);

            // Buyer Details
            Paragraph buyerTitle = new Paragraph("BUYER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(buyerTitle);

            Table buyerTable = new Table(2).setWidth(500);
            buyerTable.addCell(new Paragraph("Buyer Name:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getUsername()).setFont(unicodeFont));
            buyerTable.addCell(new Paragraph("Buyer Email:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getEmail()).setFont(unicodeFont));
            buyerTable.addCell(new Paragraph("Phone:").setFont(unicodeFont));
            buyerTable.addCell(new Paragraph(buyer.getUser().getPhoneNumber() != null ?
                    buyer.getUser().getPhoneNumber() : "Not provided").setFont(unicodeFont));
            doc.add(buyerTable);

            // Footer
            doc.add(new Paragraph("_".repeat(80))
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginTop(20)
                    .setMarginBottom(10));
            Paragraph footer = new Paragraph("Thank you for using Mazadat! This is an official receipt.")
                    .setTextAlignment(TextAlignment.CENTER)
                    .setFontSize(10);
            doc.add(footer);

            // Close document - this will automatically close PdfDocument and Writer
            doc.close();

            return baos.toByteArray();
        } catch (Exception e) {
            throw new ApiException("Error generating PDF: " + e.getMessage());
        }
    }

    private PdfFont loadUnicodeFont() {
        try {
            // If you add a bundled font later, keep this first.
            ClassPathResource bundledFont = new ClassPathResource("static/fonts/NotoNaskhArabic-Regular.ttf");
            if (bundledFont.exists()) {
                return PdfFontFactory.createFont(
                        inputStreamToByteArray(bundledFont.getInputStream()),
                        PdfEncodings.IDENTITY_H,
                        PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
                );
            }
        } catch (Exception ignored) {
            // Fallbacks below
        }

        try {
            // Windows fallback for local development/runtime.
            return PdfFontFactory.createFont(
                    "C:/Windows/Fonts/arial.ttf",
                    PdfEncodings.IDENTITY_H,
                    PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
            );
        } catch (Exception ignored) {
            // Final fallback
        }

        try {
            return PdfFontFactory.createFont();
        } catch (Exception e) {
            throw new ApiException("Unable to load a PDF font: " + e.getMessage());
        }
    }

    private byte[] inputStreamToByteArray(InputStream is) throws Exception {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[16384];
        while ((nRead = is.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }
        return buffer.toByteArray();
    }
}

package org.example.mazadat.Service;

import com.itextpdf.io.font.PdfEncodings;
import com.itextpdf.kernel.font.PdfFont;
import com.itextpdf.kernel.font.PdfFontFactory;
import com.itextpdf.io.image.ImageData;
import com.itextpdf.io.image.ImageDataFactory;
import com.itextpdf.kernel.pdf.PdfDocument;
import com.itextpdf.kernel.pdf.PdfWriter;
import com.itextpdf.layout.Document;
import com.itextpdf.layout.element.Image;
import com.itextpdf.layout.element.Paragraph;
import com.itextpdf.layout.element.Table;
import com.itextpdf.layout.properties.BaseDirection;
import com.itextpdf.layout.properties.TextAlignment;
import lombok.RequiredArgsConstructor;
import org.example.mazadat.Api.ApiException;
import org.example.mazadat.Model.Auction;
import org.example.mazadat.Model.Buyer;
import org.example.mazadat.Repository.AuctionRepository;
import org.example.mazadat.Repository.BuyerRepository;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.nio.charset.StandardCharsets;

@Service
@RequiredArgsConstructor
public class ReceiptService {

    private final AuctionRepository auctionRepository;
    private final BuyerRepository buyerRepository;

    public byte[] generateReceiptPDF(Integer auctionId, Integer buyerId) {
        // Fetch auction
        Auction auction = auctionRepository.findById(auctionId).orElse(null);
        if (auction == null) {
            throw new ApiException("Auction not found");
        }

        // Verify auction has ended
        LocalDateTime now = LocalDateTime.now();
        if (auction.getEndDate() != null && now.isBefore(auction.getEndDate())) {
            throw new ApiException("Auction has not ended yet. Receipt can only be downloaded after the auction ends.");
        }

        // Fetch buyer
        Buyer buyer = buyerRepository.findById(buyerId).orElse(null);
        if (buyer == null) {
            throw new ApiException("Buyer not found");
        }

        // Verify buyer is the winner
        if (auction.getHighestBidder() == null || !auction.getHighestBidder().equals(buyer.getUser().getUsername())) {
            throw new ApiException("Only the auction winner can generate a receipt");
        }

        // Update auction status to ENDED if not already
        if (auction.getStatus() == null || !auction.getStatus().equals("ENDED")) {
            auction.setStatus("ENDED");
            auctionRepository.save(auction);
        }

        byte[] pdfBytes = createPDF(auction, buyer);
        if (pdfBytes == null || pdfBytes.length < 16) {
            throw new ApiException("Generated receipt is empty");
        }

        String pdfHeader = new String(pdfBytes, 0, 4, StandardCharsets.US_ASCII);
        if (!"%PDF".equals(pdfHeader)) {
            throw new ApiException("Generated receipt is invalid");
        }

        return pdfBytes;
    }

    private byte[] createPDF(Auction auction, Buyer buyer) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            PdfWriter writer = new PdfWriter(baos);
            PdfDocument pdfDoc = new PdfDocument(writer);
            Document doc = new Document(pdfDoc);
            PdfFont unicodeFont = loadUnicodeFont();
            doc.setFont(unicodeFont);

            // Add logo
            try {
                ClassPathResource resource = new ClassPathResource("static/logos/mazadat_green_logo.png");
                InputStream inputStream = resource.getInputStream();
                ImageData imageData = ImageDataFactory.create(inputStreamToByteArray(inputStream));
                Image logo = new Image(imageData).setWidth(100).setHeight(100);
                doc.add(logo);
            } catch (Exception e) {
                // Logo not found, continue without it
            }

            // Title
            Paragraph title = new Paragraph("MAZADAT AUCTION RECEIPT")
                    .setFontSize(24)
                    .setBold()
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(title);

            // Receipt date
            String formattedDate = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
            Paragraph dateP = new Paragraph("Receipt Generated: " + formattedDate)
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginBottom(20);
            doc.add(dateP);

            // Divider
            doc.add(new Paragraph("_".repeat(80)).setTextAlignment(TextAlignment.CENTER).setMarginBottom(20));

            // Auction Details
            Paragraph auctionTitle = new Paragraph("AUCTION DETAILS")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(auctionTitle);

            Table auctionTable = new Table(2).setWidth(500);
            auctionTable.addCell(labelCell("Auction ID:", unicodeFont));
            auctionTable.addCell(valueCell(String.valueOf(auction.getId()), unicodeFont));
            auctionTable.addCell(labelCell("Auction Name:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getTitle() != null ? auction.getTitle() : "N/A", unicodeFont));
            auctionTable.addCell(labelCell("Auction Description:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getDescription() != null ? auction.getDescription() : "N/A", unicodeFont));
            auctionTable.addCell(labelCell("Selling Price:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getCurrentPrice() + " SR", unicodeFont));
            auctionTable.addCell(labelCell("Auction End Date:", unicodeFont));
            auctionTable.addCell(valueCell(auction.getEndDate() != null ?
                    auction.getEndDate().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss")) : "N/A", unicodeFont));
            doc.add(auctionTable);

            // Seller Details
            Paragraph sellerTitle = new Paragraph("SELLER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(sellerTitle);

            Table sellerTable = new Table(2).setWidth(500);
            sellerTable.addCell(labelCell("Seller Name:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getUser().getUsername(), unicodeFont));
            sellerTable.addCell(labelCell("Seller Email:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getUser().getEmail(), unicodeFont));
            sellerTable.addCell(labelCell("Iban:", unicodeFont));
            sellerTable.addCell(valueCell(auction.getSeller().getIban() != null ?
                    auction.getSeller().getIban() : "Not provided", unicodeFont));
            doc.add(sellerTable);

            // Buyer Details
            Paragraph buyerTitle = new Paragraph("BUYER INFORMATION")
                    .setBold()
                    .setFontSize(14)
                    .setMarginTop(20)
                    .setMarginBottom(10);
            doc.add(buyerTitle);

            Table buyerTable = new Table(2).setWidth(500);
            buyerTable.addCell(labelCell("Buyer Name:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getUsername(), unicodeFont));
            buyerTable.addCell(labelCell("Buyer Email:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getEmail(), unicodeFont));
            buyerTable.addCell(labelCell("Phone:", unicodeFont));
            buyerTable.addCell(valueCell(buyer.getUser().getPhoneNumber() != null ?
                    buyer.getUser().getPhoneNumber() : "Not provided", unicodeFont));
            doc.add(buyerTable);

            // Footer
            doc.add(new Paragraph("_".repeat(80))
                    .setTextAlignment(TextAlignment.CENTER)
                    .setMarginTop(20)
                    .setMarginBottom(10));
            Paragraph footer = new Paragraph("Thank you for using Mazadat! This is an official receipt.")
                    .setTextAlignment(TextAlignment.CENTER)
                    .setFontSize(10);
            doc.add(footer);

            // Close document - this will automatically close PdfDocument and Writer
            doc.close();

            return baos.toByteArray();
        } catch (Exception e) {
            throw new ApiException("Error generating PDF: " + e.getMessage());
        }
    }

    private Paragraph labelCell(String text, PdfFont font) {
        return new Paragraph(text)
                .setFont(font)
                .setBaseDirection(BaseDirection.LEFT_TO_RIGHT)
                .setTextAlignment(TextAlignment.LEFT);
    }

    private Paragraph valueCell(String text, PdfFont font) {
        String safe = text == null ? "" : text;
        boolean rtl = containsArabic(safe);

        return new Paragraph(safe)
                .setFont(font)
                .setBaseDirection(rtl ? BaseDirection.RIGHT_TO_LEFT : BaseDirection.LEFT_TO_RIGHT)
                .setTextAlignment(rtl ? TextAlignment.RIGHT : TextAlignment.LEFT);
    }

    private boolean containsArabic(String text) {
        if (text == null || text.isEmpty()) {
            return false;
        }
        return text.matches(".*[\\u0600-\\u06FF\\u0750-\\u077F\\u08A0-\\u08FF\\uFB50-\\uFDFF\\uFE70-\\uFEFF].*");
    }

    private PdfFont loadUnicodeFont() {
        try {
            // If you add a bundled font later, keep this first.
            ClassPathResource bundledFont = new ClassPathResource("static/fonts/NotoNaskhArabic-Regular.ttf");
            if (bundledFont.exists()) {
                return PdfFontFactory.createFont(
                        inputStreamToByteArray(bundledFont.getInputStream()),
                        PdfEncodings.IDENTITY_H,
                        PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
                );
            }
        } catch (Exception ignored) {
            // Fallbacks below
        }

        try {
            // Windows fallback for local development/runtime.
            return PdfFontFactory.createFont(
                    "C:/Windows/Fonts/arial.ttf",
                    PdfEncodings.IDENTITY_H,
                    PdfFontFactory.EmbeddingStrategy.PREFER_EMBEDDED
            );
        } catch (Exception ignored) {
            // Final fallback
        }

        try {
            return PdfFontFactory.createFont();
        } catch (Exception e) {
            throw new ApiException("Unable to load a PDF font: " + e.getMessage());
        }
    }

    private byte[] inputStreamToByteArray(InputStream is) throws Exception {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[16384];
        while ((nRead = is.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }
        return buffer.toByteArray();
    }
}

spring.application.name=Mazadat

# Database Configuration
spring.datasource.url=${SPRING_DATASOURCE_URL:jdbc:mysql://${MYSQLHOST:localhost}:${MYSQLPORT:3306}/${MYSQLDATABASE:mazadat}?useSSL=false&allowPublicKeyRetrieval=true&serverTimezone=UTC}
spring.datasource.username=${SPRING_DATASOURCE_USERNAME:${MYSQLUSER:mazadat_user}}
spring.datasource.password=${SPRING_DATASOURCE_PASSWORD:${MYSQLPASSWORD:mazadat_password}}

# JPA/Hibernate Configuration
spring.jpa.database-platform=org.hibernate.dialect.MySQL8Dialect
spring.jpa.show-sql=false
spring.jpa.generate-ddl=true
spring.jpa.hibernate.ddl-auto=${SPRING_JPA_HIBERNATE_DDL_AUTO:update}

# Error Handling
server.error.include-message=always
server.error.include-stacktrace=always

# Upload / Image Storage
mazadat.upload-dir=${MAZADAT_UPLOAD_DIR:/app/uploads}
mazadat.storage.mode=${MAZADAT_STORAGE_MODE:local}
mazadat.storage.public-base-url=${MAZADAT_IMAGE_PUBLIC_BASE_URL:}
mazadat.storage.s3.endpoint=${MAZADAT_S3_ENDPOINT:}
mazadat.storage.s3.region=${MAZADAT_S3_REGION:us-east-1}
mazadat.storage.s3.bucket=${MAZADAT_S3_BUCKET:}
mazadat.storage.s3.access-key=${MAZADAT_S3_ACCESS_KEY:}
mazadat.storage.s3.secret-key=${MAZADAT_S3_SECRET_KEY:}
mazadat.storage.s3.path-prefix=${MAZADAT_S3_PATH_PREFIX:images}

# Server Configuration
server.port=${PORT:${SERVER_PORT:8080}}
server.servlet.context-path=/

# CORS Configuration
mazadat.cors.allowed-origins=${MAZADAT_CORS_ALLOWED_ORIGINS:http://localhost:5173,http://localhost:3000,http://127.0.0.1:5173,http://127.0.0.1:3000}
mazadat.cors.allowed-methods=GET,POST,PUT,DELETE,OPTIONS,PATCH
mazadat.cors.allowed-headers=*
mazadat.cors.max-age=3600

# Actuator / Health
management.endpoints.web.exposure.include=health,info
management.endpoint.health.probes.enabled=true

# Logging
logging.level.root=INFO
logging.level.org.springframework=INFO
logging.level.org.example.mazadat=DEBUG

